{
  "name": "noid-ai-studio",
  "version": "1.0.0",
  "description": "NOID Health AI Studio - Advanced Functional Diagnostics Interface",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1",
    "lucide-react": "^0.468.0"
  },
  "devDependencies": {
    "@types/react": "^18.3.12",
    "@types/react-dom": "^18.3.1",
    "@vitejs/plugin-react": "^4.3.4",
    "autoprefixer": "^10.4.20",
    "postcss": "^8.4.49",
    "tailwindcss": "^3.4.16",
    "vite": "^6.0.5"
  }
}

import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";
import "./index.css";

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);

// src/App.jsx
import React, { useState, useEffect, useMemo } from "react";
import {
  Activity,
  User,
  FileText,
  Database,
  Brain,
  Heart,
  Zap,
  Shield,
  ChevronRight,
  ChevronDown,
  Save,
  Eye,
  Download,
  Search,
  CheckCircle2,
  AlertCircle,
  Plus,
  Info,
  Layers,
  Thermometer,
  Wind,
  Files,
  File,
  X,
  Send,
  PanelRightClose,
  PanelRightOpen,
  MoreVertical,
  Edit3,
} from "lucide-react";

// --- Types & Initial State ---

const INITIAL_CLIENT_DATA = {
  id: "CL-7729",
  name: "Erik Johansson",
  age: 48,
  sex: "Male",
  date: new Date().toLocaleDateString(),
  therapist: "Dr. Sarah Smith",
  visitType: "Initial Assessment",
};

const INITIAL_FILES = [
  {
    id: "f1",
    title: "Behandlingsplan_Mars.md",
    content:
      "# Behandlingsplan\n\nFokusområden:\n1. Reglering av SVR\n2. Stöd för leveravgiftning\n3. Optimering av sömnkvalitet",
  },
  {
    id: "f2",
    title: "Journalanteckningar_2024.txt",
    content:
      "Patienten rapporterar förbättrad energi på morgonen men kvarstående trötthet efter kl 15:00.",
  },
];

const MODULE_DATA = {
  heart: [
    {
      id: "ci",
      name: "Cardiac Index",
      value: "2.4",
      unit: "L/min/m²",
      ref: "2.6 – 4.0",
      status: "strained",
      score: 2,
    },
    {
      id: "sv",
      name: "Stroke Volume",
      value: "65",
      unit: "ml/beat",
      ref: "60 – 100",
      status: "optimal",
      score: 0,
    },
    {
      id: "svr",
      name: "SVR",
      value: "1450",
      unit: "dyn·s/cm⁵",
      ref: "800 – 1200",
      status: "critical",
      score: 3,
    },
    {
      id: "no",
      name: "Nitric Oxide (NO)",
      value: "18",
      unit: "μmol/L",
      ref: "20 – 40",
      status: "strained",
      score: 2,
    },
  ],
  ans: [
    {
      id: "hr",
      name: "Heart Rate",
      value: "78",
      unit: "bpm",
      ref: "60 – 80",
      status: "optimal",
      score: 0,
    },
    {
      id: "lfhf",
      name: "LF/HF Ratio",
      value: "3.2",
      unit: "ratio",
      ref: "0.5 – 2.0",
      status: "strained",
      score: 2,
    },
    {
      id: "rmssd",
      name: "RMSSD",
      value: "18",
      unit: "ms",
      ref: "20 – 50",
      status: "strained",
      score: 2,
    },
  ],
  metabolism: [
    {
      id: "bmi",
      name: "BMI",
      value: "26.4",
      unit: "kg/m²",
      ref: "18.5 – 24.9",
      status: "fair",
      score: 1,
    },
    {
      id: "fat",
      name: "Fat Mass",
      value: "24",
      unit: "%",
      ref: "15 – 22",
      status: "fair",
      score: 1,
    },
  ],
  nls: {
    brain: {
      findings: "Indikation på kognitiv belastning.",
      interpretation: "Möjlig koppling till låg CI.",
      relevance: "Medium",
      compensation: false,
    },
    liver: {
      findings: "Nedsatt signalrespons i avgiftningsfas II.",
      interpretation: "Behöver metabolt stöd.",
      relevance: "High",
      compensation: true,
    },
    gut: {
      findings: "Inflammatorisk profil i tunntarm.",
      interpretation: "Möjlig roten till systemisk SVR-stegring.",
      relevance: "High",
      compensation: false,
    },
  },
};

const PARAMETER_LIBRARY = {
  ci: {
    def: "Hjärtminutvolym i förhållande till kroppsstorlek.",
    low: "Minskad hjärtfunktion, låg cirkulation, låg energi/mitokondriell aktivitet.",
    high: "Stressrespons, kompensatoriskt överskottsarbete.",
    significance: "Avgör hur effektivt syre och näringsämnen distribueras.",
    correlations: "Stroke Volume, SVR, HR, NO.",
    compensation: "Ja – kroppen kan öka hjärtfrekvens eller kärlmotstånd.",
  },
  svr: {
    def: "Motstånd i blodkärlen.",
    low: "Vasodilatation, potentiellt svag reglering.",
    high: "Stress, inflammation, artärstyvhet, sympatikusaktivering.",
    significance: "Avgör hur hårt hjärtat måste arbeta.",
    correlations: "Cardiac Index, Blodtryck.",
    compensation: "Ja – hög SVR kan kompensera för låg pumpkapacitet.",
  },
};

// --- Helper Components ---

const StatusBadge = ({ score }) => {
  const colors = [
    "bg-emerald-500/10 text-emerald-500 border-emerald-500/20",
    "bg-yellow-500/10 text-yellow-500 border-yellow-500/20",
    "bg-orange-500/10 text-orange-500 border-orange-500/20",
    "bg-red-500/10 text-red-500 border-red-500/20",
    "bg-red-700/10 text-red-700 border-red-700/20",
  ];
  const labels = ["Optimal", "Fair", "Strained", "Critical", "Severe"];
  return (
    <span
      className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${colors[score] || colors[0]}`}
    >
      {labels[score] || "Optimal"}
    </span>
  );
};

// --- Main App ---

export default function App() {
  const [activeTab, setActiveTab] = useState("input");
  const [activeModule, setActiveModule] = useState("heart");
  const [client, setClient] = useState(INITIAL_CLIENT_DATA);
  const [data, setData] = useState(MODULE_DATA);
  const [aiWorking, setAiWorking] = useState(false);
  const [reportApproved, setReportApproved] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Files State
  const [files, setFiles] = useState(INITIAL_FILES);
  const [activeFileId, setActiveFileId] = useState("f1");

  // AI Agent Panel State
  const [isAiPanelOpen, setIsAiPanelOpen] = useState(true);
  const [chatInput, setChatInput] = useState("");
  const [chatHistory, setChatHistory] = useState([
    {
      role: "assistant",
      text: "Hej Sarah! Jag har analyserat Eriks senaste testdata. SVR är fortfarande kritiskt hög. Vill du att jag utkastet för en behandlingsplan baserat på detta?",
    },
  ]);

  const activeFile = useMemo(
    () => files.find((f) => f.id === activeFileId),
    [files, activeFileId],
  );

  const wellnessIndex = useMemo(() => {
    let totalScore = 0;
    let count = 0;
    Object.values(data).forEach((mod) => {
      if (Array.isArray(mod)) {
        mod.forEach((p) => {
          if (p.value !== "") {
            totalScore += p.score;
            count++;
          }
        });
      }
    });
    if (count === 0) return 100;
    const avgPenalty = (totalScore / (count * 4)) * 100;
    return Math.max(0, Math.round(100 - avgPenalty));
  }, [data]);

  const updateParam = (mod, id, field, value) => {
    const newData = { ...data };
    const param = newData[mod].find((p) => p.id === id);
    param[field] = value;
    setData(newData);
  };

  const updateNLS = (organ, field, value) => {
    setData((prev) => ({
      ...prev,
      nls: {
        ...prev.nls,
        [organ]: { ...prev.nls[organ], [field]: value },
      },
    }));
  };

  const updateFileContent = (newContent) => {
    setFiles((prev) =>
      prev.map((f) =>
        f.id === activeFileId ? { ...f, content: newContent } : f,
      ),
    );
  };

  const createNewFile = () => {
    const newId = `f${Date.now()}`;
    const newFile = { id: newId, title: "Namnlös_Fil.md", content: "" };
    setFiles([...files, newFile]);
    setActiveFileId(newId);
  };

  const handleSendMessage = () => {
    if (!chatInput.trim()) return;
    const newUserMsg = { role: "user", text: chatInput };
    setChatHistory([...chatHistory, newUserMsg]);
    setChatInput("");

    // Fake AI Response
    setTimeout(() => {
      setChatHistory((prev) => [
        ...prev,
        {
          role: "assistant",
          text: "Jag förstår. Baserat på datan rekommenderar jag att vi fokuserar på kväveoxid-stöd för att sänka SVR. Vill du att jag lägger till detta i dokumentet?",
        },
      ]);
    }, 1000);
  };

  const handleAiGen = () => {
    setAiWorking(true);
    setTimeout(() => {
      setAiWorking(false);
    }, 1500);
  };

  return (
    <div className="flex h-screen w-full bg-[#0d1117] text-[#c9d1d9] font-sans selection:bg-blue-500/30 overflow-hidden">
      {/* Sidebar - Navigation */}
      <nav className="w-16 md:w-60 border-r border-[#30363d] bg-[#161b22] flex flex-col shrink-0">
        <div className="p-4 border-b border-[#30363d] flex items-center gap-3">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
            <Zap className="text-white w-5 h-5" />
          </div>
          <span className="hidden md:block font-bold text-white tracking-tight">
            NOID STUDIO
          </span>
        </div>

        <div className="flex-1 py-4 space-y-1 overflow-y-auto px-2">
          <div className="px-3 mb-2 text-[10px] font-bold text-gray-500 uppercase tracking-widest hidden md:block">
            IDE Sections
          </div>

          <button
            onClick={() => setActiveTab("input")}
            className={`w-full flex items-center gap-3 px-3 py-2 rounded-md transition-colors ${activeTab === "input" ? "bg-blue-600/10 text-blue-400" : "hover:bg-[#21262d]"}`}
          >
            <Layers className="w-5 h-5 shrink-0" />
            <span className="hidden md:block text-xs font-medium truncate text-white">
              {m.label}
            </span>
          </button>

          <button
            onClick={() => setActiveTab("files")}
            className={`w-full flex items-center gap-3 px-3 py-2 rounded-md transition-colors ${activeTab === "files" ? "bg-blue-600/10 text-blue-400" : "hover:bg-[#21262d]"}`}
          >
            <Files className="w-5 h-5 shrink-0" />
            <span className="hidden md:block text-xs font-medium truncate text-white">
              Files
            </span>
          </button>

          <button
            onClick={() => setActiveTab("preview")}
            className={`w-full flex items-center gap-3 px-3 py-2 rounded-md transition-colors ${activeTab === "preview" ? "bg-blue-600/10 text-blue-400" : "hover:bg-[#21262d]"}`}
          >
            <Eye className="w-5 h-5 shrink-0" />
            <span className="hidden md:block text-xs font-medium truncate text-white">
              Report Preview
            </span>
          </button>

          <button
            onClick={() => setActiveTab("library")}
            className={`w-full flex items-center gap-3 px-3 py-2 rounded-md transition-colors ${activeTab === "library" ? "bg-blue-600/10 text-blue-400" : "hover:bg-[#21262d]"}`}
          >
            <Database className="w-5 h-5 shrink-0" />
            <span className="hidden md:block text-xs font-medium truncate text-white">
              Library
            </span>
          </button>

          <div className="pt-6 px-3 mb-2 text-[10px] font-bold text-gray-500 uppercase tracking-widest hidden md:block">
            Diagnostics
          </div>

          {[
            { id: "heart", icon: Heart, label: "Heart & Circ." },
            { id: "ans", icon: Activity, label: "Nervous Sys." },
            { id: "metabolism", icon: Thermometer, label: "Metabolism" },
            { id: "nls", icon: Brain, label: "Signal Resp." },
          ].map((m) => (
            <button
              key={m.id}
              onClick={() => {
                setActiveModule(m.id);
                setActiveTab("input");
              }}
              className={`w-full flex items-center gap-3 px-3 py-2 rounded-md transition-colors ${activeModule === m.id && activeTab === "input" ? "text-white bg-[#21262d]" : "text-gray-400 hover:bg-[#21262d]"}`}
            >
              <m.icon
                className={`w-4 h-4 shrink-0 ${activeModule === m.id && activeTab === "input" ? "text-blue-500" : ""}`}
              />
              <span className="hidden md:block text-xs truncate text-white">
                {m.label}
              </span>
            </button>
          ))}
        </div>

        <div className="p-4 border-t border-[#30363d]">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-full bg-blue-900 border border-blue-400/30 flex items-center justify-center text-[10px] font-bold">
              SS
            </div>
            <div className="hidden md:block">
              <p className="text-xs font-semibold text-white">Sarah Smith</p>
              <p className="text-[10px] text-gray-500 uppercase">Clinician</p>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Container (Canvas + AI Panel) */}
      <div className="flex-1 flex overflow-hidden">
        {/* Central Workspace */}
        <main
          className={`flex-1 flex flex-col bg-[#0d1117] overflow-hidden min-w-0 border-r border-[#30363d] transition-all duration-300 ${isSidebarOpen ? "min-w-0" : "min-w-0 ml-16"}`}
        >
          {/* Header Bar */}
          <header className="h-14 border-b border-[#30363d] bg-[#161b22] px-4 flex items-center justify-between shrink-0">
            <div className="flex items-center gap-4 min-w-0">
              <h2 className="text-sm font-semibold flex items-center gap-2 truncate">
                <User className="w-4 h-4 text-gray-400 shrink-0" />
                {client.name}
                <span className="text-gray-500 font-normal hidden sm:inline">
                  ({client.id})
                </span>
              </h2>
              <div className="h-4 w-px bg-[#30363d]"></div>
              <div className="flex items-center gap-2">
                <span
                  className={`w-2 h-2 rounded-full ${wellnessIndex > 70 ? "bg-emerald-500" : wellnessIndex > 40 ? "bg-orange-500" : "bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"}`}
                ></span>
                <span className="text-xs font-mono text-gray-400">
                  Idx: {wellnessIndex}%
                </span>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <button
                onClick={handleAiGen}
                className={`flex items-center gap-2 px-3 py-1.5 rounded text-xs font-medium transition-all ${aiWorking ? "bg-blue-600/50 cursor-not-allowed" : "bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/20"}`}
              >
                {aiWorking ? (
                  <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  <Brain className="w-3.5 h-3.5" />
                )}
                <span className="hidden sm:inline">Analyze Data</span>
              </button>

              <button
                onClick={() => setIsAiPanelOpen(!isAiPanelOpen)}
                className={`p-1.5 rounded hover:bg-[#30363d] border border-[#30363d] transition-colors ${isAiPanelOpen ? "bg-[#30363d] text-blue-400" : "text-gray-400"}`}
              >
                {isAiPanelOpen ? (
                  <PanelRightClose className="w-4 h-4" />
                ) : (
                  <PanelRightOpen className="w-4 h-4" />
                )}
              </button>

              <button
                onClick={() => setIsSidebarOpen(!isSidebarOpen)}
                className={`p-1.5 rounded hover:bg-[#30363d] border border-[#30363d] transition-colors ${isSidebarOpen ? "text-gray-400" : "text-white bg-[#21262d]"}`}
              >
                <Layers className="w-4 h-4" />
              </button>
            </div>
          </header>

          {/* Canvas Content */}
          <div className="flex-1 overflow-y-auto">
            {activeTab === "files" && (
              <div className="flex h-full animate-in fade-in duration-300">
                {/* File Explorer Sidebar */}
                <div className="w-56 border-r border-[#30363d] bg-[#0d1117] flex flex-col shrink-0">
                  <div className="p-3 flex items-center justify-between">
                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">
                      Explorer
                    </span>
                    <button
                      onClick={createNewFile}
                      className="p-1 hover:bg-[#21262d] rounded transition-colors"
                    >
                      <Plus className="w-4 h-4 text-gray-400" />
                    </button>
                  </div>
                  <div className="flex-1 overflow-y-auto px-2 space-y-0.5">
                    {files.map((f) => (
                      <button
                        key={f.id}
                        onClick={() => setActiveFileId(f.id)}
                        className={`w-full text-left px-2 py-1.5 rounded text-xs flex items-center gap-2 group transition-colors ${activeFileId === f.id ? "bg-[#21262d] text-blue-400" : "text-gray-400 hover:bg-[#161b22]"}`}
                      >
                        <File className="w-3.5 h-3.5" />
                        <span className="truncate flex-1">{f.title}</span>
                        {activeFileId === f.id && (
                          <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                        )}
                      </button>
                    ))}
                  </div>
                </div>

                {/* File Editor */}
                <div className="flex-1 flex flex-col bg-[#0d1117]">
                  {activeFile ? (
                    <>
                      <div className="h-10 bg-[#161b22] border-b border-[#30363d] flex items-center px-4 gap-2">
                        <File className="w-3.5 h-3.5 text-blue-400" />
                        <span className="text-xs font-mono text-gray-400">
                          {activeFile.title}
                        </span>
                        <div className="ml-auto flex items-center gap-2">
                          <button className="p-1 hover:bg-[#30363d] rounded">
                            <Save className="w-3.5 h-3.5 text-gray-500" />
                          </button>
                        </div>
                      </div>
                      <textarea
                        className="flex-1 w-full bg-[#0d1117] text-[#c9d1d9] font-mono text-sm p-8 outline-none resize-none leading-relaxed"
                        value={activeFile.content}
                        onChange={(e) => updateFileContent(e.target.value)}
                        placeholder="Starta dokumentation här..."
                        spellCheck="false"
                      ></textarea>
                    </>
                  ) : (
                    <div className="flex-1 flex items-center justify-center text-gray-600 flex-col gap-2">
                      <Files className="w-12 h-12 opacity-20" />
                      <p className="text-sm">
                        Välj en fil för att börja skriva
                      </p>
                    </div>
                  )}
                </div>
              </div>
            )}

            {activeTab === "input" && (
              <div className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 animate-in slide-in-from-bottom-4 duration-500">
                <div className="border-b border-[#30363d] pb-4">
                  <div className="text-xs font-bold text-blue-500 uppercase tracking-widest mb-1">
                    Module Editor
                  </div>
                  <h1 className="text-2xl font-bold text-white capitalize tracking-tight">
                    {activeModule.replace("_", " ")}
                  </h1>
                </div>

                {activeModule !== "nls" ? (
                  <div className="grid grid-cols-1 gap-4">
                    {data[activeModule].map((p) => (
                      <div
                        key={p.id}
                        className="bg-[#161b22] border border-[#30363d] rounded-lg p-4 group hover:border-blue-500/30 transition-all shadow-sm"
                      >
                        <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
                          <div>
                            <h4 className="text-sm font-semibold text-[#f0f6fc]">
                              {p.name}
                            </h4>
                            <p className="text-[10px] text-gray-500">
                              Ref: {p.ref} {p.unit}
                            </p>
                          </div>
                          <div className="flex items-center gap-4">
                            <div className="flex flex-col gap-1">
                              <label className="text-[10px] font-bold text-gray-500 uppercase">
                                Measured
                              </label>
                              <input
                                type="text"
                                value={p.value}
                                onChange={(e) =>
                                  updateParam(
                                    activeModule,
                                    p.id,
                                    "value",
                                    e.target.value,
                                  )
                                }
                                className="bg-[#0d1117] border border-[#30363d] rounded px-3 py-1.5 text-sm w-24 focus:border-blue-500 outline-none transition-colors font-mono"
                              />
                            </div>
                            <div className="flex flex-col gap-1">
                              <label className="text-[10px] font-bold text-gray-500 uppercase">
                                Score
                              </label>
                              <select
                                value={p.score}
                                onChange={(e) =>
                                  updateParam(
                                    activeModule,
                                    p.id,
                                    "score",
                                    parseInt(e.target.value),
                                  )
                                }
                                className="bg-[#0d1117] border border-[#30363d] rounded px-3 py-1.5 text-sm focus:border-blue-500 outline-none transition-colors"
                              >
                                {[0, 1, 2, 3, 4].map((v) => (
                                  <option key={v} value={v}>
                                    {v}
                                  </option>
                                ))}
                              </select>
                            </div>
                            <div className="pt-4">
                              <StatusBadge score={p.score} />
                            </div>
                          </div>
                        </div>
                        <div className="relative">
                          <textarea
                            placeholder="Lägg till klinisk observation..."
                            className="w-full bg-[#0d1117] border border-[#30363d] rounded p-2 text-xs h-16 focus:border-blue-500 outline-none resize-none"
                          ></textarea>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="space-y-6">
                    {Object.entries(data.nls).map(([organ, vals]) => (
                      <div
                        key={organ}
                        className="bg-[#161b22] border border-[#30363d] rounded-lg overflow-hidden shadow-md"
                      >
                        <div className="bg-[#21262d] px-4 py-2 border-b border-[#30363d] flex items-center justify-between">
                          <h3 className="text-sm font-bold capitalize flex items-center gap-2">
                            <div className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.5)]"></div>
                            {organ} Analysis
                          </h3>
                          <div className="flex items-center gap-3">
                            <label className="flex items-center gap-2 text-[10px] cursor-pointer text-gray-400 font-bold uppercase">
                              <input
                                type="checkbox"
                                checked={vals.compensation}
                                onChange={(e) =>
                                  updateNLS(
                                    organ,
                                    "compensation",
